// Process all incoming issues and return one output per input item.
const items = $input.all();

// ---------- helpers ----------
const safe = (v, fb = "—") => (v === 0 || (v && v !== "")) ? v : fb;

const getRepoFullName = (repositoryUrl) => {
  // e.g., https://api.github.com/repos/owner/repo
  const m = String(repositoryUrl || "").match(/repos\/([^/]+)\/([^/]+)/i);
  return m ? `${m[1]}/${m[2]}` : null;
};

const getRepoHtmlUrl = (fullName) => (fullName ? `https://github.com/${fullName}` : null);

const truncate = (text, max = 500) => {
  if (!text) return null;
  const trimmed = String(text).replace(/\s+/g, " ").trim();
  return trimmed.length <= max ? trimmed : trimmed.slice(0, max - 1) + "…";
};

const formatDate = (iso) => {
  if (!iso) return "—";
  try {
    const d = new Date(iso);
    return d.toISOString().replace("T", " ").replace("Z", " UTC");
  } catch {
    return iso;
  }
};

const sumReactions = (reactionsObj) => {
  if (!reactionsObj || typeof reactionsObj !== "object") return 0;
  const keys = ["+1", "-1", "laugh", "hooray", "confused", "heart", "rocket", "eyes"];
  return keys.reduce((acc, k) => acc + (Number(reactionsObj[k]) || 0), 0);
};

// Build blocks for a single issue JSON (shape = your GitHub issue object)
const buildBlocks = (issue) => {
  const title       = safe(issue.title, "Untitled issue");
  const number      = safe(issue.number, "—");
  const state       = safe(issue.state, "—");
  const issueUrl    = issue.html_url || "https://github.com";
  const createdAt   = formatDate(issue.created_at);
  const updatedAt   = formatDate(issue.updated_at);
  const reporter    = (issue.user && issue.user.login) ? issue.user.login : "unknown";
  const labels      = Array.isArray(issue.labels) ? issue.labels : [];
  const labelsText  = labels.length ? labels.map(l => `\`${l.name}\``).join(" ") : "—";
  const reactions   = sumReactions(issue.reactions);
  const repoFull    = getRepoFullName(issue.repository_url);
  const repoHtml    = getRepoHtmlUrl(repoFull);
  const bodyPreview = truncate(issue.body, 600);

  const blocks = [];

  // Header
  blocks.push({
    type: "header",
    text: { type: "plain_text", text: `🐛 Bug #${number}: ${title}`, emoji: true }
  });

  // Repo + Reporter
  blocks.push({
    type: "section",
    fields: [
      { type: "mrkdwn", text: `*Repository:*\n${repoHtml ? `<${repoHtml}|${repoFull}>` : safe(repoFull)}` },
      { type: "mrkdwn", text: `*Submitted By:*\n${reporter}` }
    ]
  });

  // Labels + State
  blocks.push({
    type: "section",
    fields: [
      { type: "mrkdwn", text: `*Labels:*\n${labelsText}` },
      { type: "mrkdwn", text: `*State:*\n${String(state).toUpperCase()}` }
    ]
  });

  // Timestamps + Reactions
  blocks.push({
    type: "context",
    elements: [
      { type: "mrkdwn", text: `*Created:* ${createdAt}` },
      { type: "mrkdwn", text: `*Updated:* ${updatedAt}` },
      { type: "mrkdwn", text: `*Reactions:* ${reactions}` }
    ]
  });

  // Body preview
  if (bodyPreview) {
    blocks.push({ type: "divider" });
    blocks.push({
      type: "section",
      text: { type: "mrkdwn", text: `*Description*\n${bodyPreview}` }
    });
  }

  // Actions
  blocks.push({
    type: "actions",
    elements: [
      { type: "button", text: { type: "plain_text", text: "View Issue" }, url: issueUrl, style: "primary" },
      ...(repoHtml ? [{ type: "button", text: { type: "plain_text", text: "View Repo" }, url: repoHtml }] : [])
    ]
  });

  return { text: `Bug #${number}: ${title}`, blocks };
};

// ---------- map over all inputs ----------
return items.map((it) => {
  const issue = it?.json || {};
  const payload = buildBlocks(issue);
  return {
    json: {
      text: payload.text,                 // nice fallback for Slack
      slackBlock: { blocks: payload.blocks } // keep your existing shape
    }
  };
});

